class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) {
        n = characters.size();
        k = combinationLength;
        str = characters;
        idx = 0;
        generate();
    }

    string next() {
        string res = str.substr(idx, k);
        idx += k;
        return res;
    }

    bool hasNext() {
        return idx <= n - k;
    }
private:
    int n, k;
    string str;
    int idx;
    void generate() {
        do {
            idx = 0;
            generateHelper(str, k, 0);
        } while (nextPermutation(str));
    }
    void generateHelper(string& str, int k, int start) {
        if (k == 0) return;
        for (int i = start; i < str.size(); ++i) {
            swap(str[start], str[i]);
            generateHelper(str, k - 1, start + 1);
            swap(str[start], str[i]);
        }
    }
    bool nextPermutation(string& str) {
        int i = str.size() - 2;
        while (i >= 0 && str[i + 1] <= str[i]) --i;
        if (i < 0) return false;
        int j = str.size() - 1;
        while (str[j] <= str[i]) --j;
        swap(str[i], str[j]);
        int left = i + 1, right = str.size() - 1;
        while (left < right) {
            swap(str[left], str[right]);
            ++left;
            --right;
        }
        return true;
    }
};
```

